package docprose

import (
	"fmt"
	"regexp"
	"strings"
	"unicode"
)

type Mode string

const (
	ModeTechnical Mode = "technical"
	ModePlanning  Mode = "planning"
	ModePublic    Mode = "public"
)

type Checker struct {
	mode       Mode
	rules      []ruleSpec
	vocabulary Vocabulary
}

func NewChecker(mode Mode, vocabulary Vocabulary) (*Checker, error) {
	if mode == "" {
		mode = ModeTechnical
	}
	rules, err := loadRulePack(string(mode))
	if err != nil {
		return nil, err
	}
	defaultVocab, err := loadDefaultVocabulary()
	if err != nil {
		return nil, err
	}
	if len(vocabulary.Accept) == 0 {
		vocabulary.Accept = defaultVocab.Accept
	}
	if len(vocabulary.Reject) == 0 {
		vocabulary.Reject = defaultVocab.Reject
	}
	return &Checker{
		mode:       mode,
		rules:      rules,
		vocabulary: vocabulary,
	}, nil
}

func (c *Checker) Findings(file, text string) []Finding {
	var findings []Finding
	lines := strings.Split(text, "\n")

	for idx, raw := range lines {
		lineNo := idx + 1
		line := strings.TrimSpace(raw)
		if line == "" {
			continue
		}

		for _, rule := range c.rules {
			if rule.Kind == "repeated_opening" {
				if repeatedOpeningKey(line) != "" {
					findings = append(findings, Finding{
						File:          file,
						Line:          lineNo,
						RuleID:        rule.ID,
						Severity:      rule.Severity,
						Rationale:     rule.Rationale,
						SuggestedEdit: rule.SuggestedEdit,
					})
				}
				continue
			}
			if matchesRule(line, rule) {
				findings = append(findings, Finding{
					File:          file,
					Line:          lineNo,
					RuleID:        rule.ID,
					Severity:      rule.Severity,
					Rationale:     rule.Rationale,
					SuggestedEdit: rule.SuggestedEdit,
				})
			}
		}

		findings = append(findings, c.vocabularyFindings(file, lineNo, line)...)
	}

	return findings
}

func (c *Checker) vocabularyFindings(file string, lineNo int, line string) []Finding {
	var findings []Finding
	lower := strings.ToLower(line)
	for _, reject := range c.vocabulary.Reject {
		if reject == "" {
			continue
		}
		if !containsWord(lower, reject) {
			continue
		}
		if c.termAccepted(reject) {
			continue
		}
		findings = append(findings, Finding{
			File:          file,
			Line:          lineNo,
			RuleID:        "prose.vocabulary.reject",
			Severity:      "warning",
			Rationale:     fmt.Sprintf("The vocabulary term %q is discouraged in default prose because it is too generic.", reject),
			SuggestedEdit: fmt.Sprintf("Replace %q with the project-specific term or concrete noun that names the actual concept.", reject),
		})
	}
	return findings
}

func (c *Checker) termAccepted(term string) bool {
	for _, accept := range c.vocabulary.Accept {
		if accept == "" {
			continue
		}
		if strings.EqualFold(strings.TrimSpace(accept), strings.TrimSpace(term)) {
			return true
		}
	}
	return false
}

func matchesRule(line string, rule ruleSpec) bool {
	if len(rule.ContainsAny) == 0 {
		return false
	}
	if isMarkdownStructureLine(line) {
		return false
	}
	lower := strings.ToLower(line)
	matched := false
	for _, phrase := range rule.ContainsAny {
		if phrase == "" {
			continue
		}
		if strings.Contains(lower, strings.ToLower(phrase)) {
			matched = true
			break
		}
	}
	if !matched {
		return false
	}
	if strings.HasSuffix(rule.ID, ".claims") {
		return unsupportedClaim(line)
	}
	return true
}

func isMarkdownStructureLine(line string) bool {
	trimmed := strings.TrimSpace(line)
	if trimmed == "" {
		return true
	}
	if strings.HasPrefix(trimmed, "#") || strings.HasPrefix(trimmed, "---") {
		return true
	}
	if strings.HasPrefix(trimmed, "|") && strings.HasSuffix(trimmed, "|") {
		return true
	}
	if strings.Contains(trimmed, ".md") || strings.Contains(trimmed, ".yaml") || strings.Contains(trimmed, ".json") {
		return true
	}
	if strings.HasPrefix(trimmed, "- ") && len(strings.Fields(trimmed)) <= 8 {
		return true
	}
	return false
}

func unsupportedClaim(line string) bool {
	lower := strings.ToLower(line)
	if containsAny(lower, []string{
		"seamless",
		"industry-leading",
		"world-class",
		"best-in-class",
		"cutting-edge",
	}) {
		return true
	}
	if unsupportedComprehensiveClaim(lower) {
		return true
	}
	if hasEmpiricalOrCheckContext(lower) {
		return false
	}
	if unsupportedBenefitClaim(lower) {
		return true
	}
	if countMatches(lower, []string{"robust", "comprehensive", "smooth", "elegant", "excited", "high"}) >= 2 {
		return true
	}
	if countWords(line) <= 8 {
		return true
	}
	return containsAny(lower, []string{
		"experience for everyone",
		"path forward",
		"broadly useful",
		"easy to adopt",
	})
}

func unsupportedComprehensiveClaim(lower string) bool {
	if !strings.Contains(lower, "comprehensive") {
		return false
	}
	return containsAny(lower, []string{
		"comprehensive prd",
		"comprehensive implementation plan",
		"comprehensive plan",
		"comprehensive checklist",
		"comprehensive checklists",
		"comprehensive tests",
		"comprehensive documentation",
	})
}

func unsupportedBenefitClaim(lower string) bool {
	return containsAny(lower, []string{
		"better alignment",
		"better pattern",
		"better tools",
		"complex problems",
		"cutting edge",
		"powerful commands",
		"productive ways",
		"sophisticated autonomous",
		"sophisticated control flow",
		"sophisticated multi-agent",
		"true power",
	})
}

func hasEmpiricalOrCheckContext(lower string) bool {
	return containsAny(lower, []string{
		"reproduced",
		"measured",
		"benchmark",
		"test",
		"coverage",
		"contract",
		"verifiable",
		"quality-lifting pattern",
		"risk",
		"mitigation",
	})
}

func containsAny(s string, needles []string) bool {
	for _, needle := range needles {
		if strings.Contains(s, needle) {
			return true
		}

		}
	}
	return false
}

func countMatches(s string, needles []string) int {
	var count int
	for _, needle := range needles {
		if strings.Contains(s, needle) {
			count++
		}
	}
	return count
}

func countWords(s string) int {
	return len(strings.Fields(s))
}

func repeatedOpeningKey(line string) string {
	first, rest, ok := cutSentence(line)
	if !ok {
		return ""
	}
	second, _, ok := cutSentence(rest)
	if !ok {
		return ""
	}
	first = normalizeSentence(first)
	second = normalizeSentence(second)
	if first == "" || first != second {
		return ""
	}
	return first
}

func cutSentence(s string) (head, tail string, ok bool) {
	s = strings.TrimSpace(s)
	if s == "" {
		return "", "", false
	}
	for i, r := range s {
		if r == '.' || r == '!' || r == '?' {
			return strings.TrimSpace(s[:i+1]), strings.TrimSpace(s[i+1:]), true
		}
	}
	return "", "", false
}

func normalizeSentence(s string) string {
	s = strings.ToLower(strings.TrimSpace(s))
	s = strings.TrimFunc(s, func(r rune) bool {
		return unicode.IsPunct(r) || unicode.IsSpace(r)
	})
	s = strings.Join(strings.Fields(s), " ")
	return s
}

func containsWord(haystack, needle string) bool {
	needle = strings.TrimSpace(needle)
	if needle == "" {
		return false
	}
	pattern := `(?i)(^|[^[:alnum:]_])` + regexp.QuoteMeta(needle) + `([^[:alnum:]_]|$)`
	return regexp.MustCompile(pattern).FindStringIndex(haystack) != nil
}

package docprose

import (
	"fmt"
	"os"
	"path/filepath"
	"runtime"

	"gopkg.in/yaml.v3"
)

const assetRootDir = "library/checks/prose-quality"

type defaultConfig struct {
	Mode       string     `yaml:"mode"`
	Severity   string     `yaml:"severity"`
	Policy     string     `yaml:"policy"`
	Runner     string     `yaml:"runner"`
	Vale       ValeConfig `yaml:"vale"`
	StylePack  StylePack  `yaml:"rule_pack"`
	Includes   []string   `yaml:"includes"`
	Excludes   []string   `yaml:"excludes"`
	Vocabulary Vocabulary `yaml:"vocabulary"`
}

type ValeConfig struct {
	Version    string `yaml:"version"`
	StylesPath string `yaml:"styles_path"`
	Style      string `yaml:"style"`
}

type StylePack struct {
	Name    string      `yaml:"name"`
	Version string      `yaml:"version"`
	Path    string      `yaml:"path"`
	Rules   []StyleRule `yaml:"rules"`
}

type StyleRule struct {
	File   string `yaml:"file"`
	RuleID string `yaml:"rule_id"`
}

type rulePack struct {
	Mode  string     `yaml:"mode"`
	Rules []ruleSpec `yaml:"rules"`
}

type ruleSpec struct {
	ID            string   `yaml:"id"`
	Severity      string   `yaml:"severity"`
	Rationale     string   `yaml:"rationale"`
	SuggestedEdit string   `yaml:"suggested_edit"`
	ContainsAny   []string `yaml:"contains_any,omitempty"`
	Kind          string   `yaml:"kind,omitempty"`
}

type Vocabulary struct {
	DefaultPath string   `yaml:"default_path,omitempty"`
	ValeStyle   string   `yaml:"vale_style,omitempty"`
	Accept      []string `yaml:"accept"`
	Reject      []string `yaml:"reject"`
}

func defaultAssetRoot() (string, error) {
	_, file, _, ok := runtime.Caller(0)
	if !ok {
		return "", fmt.Errorf("locate docprose assets: runtime caller unavailable")
	}
	dir := filepath.Dir(file)
	root := filepath.Clean(filepath.Join(dir, "..", "..", ".."))
	return filepath.Join(root, assetRootDir), nil
}

func loadDefaultConfig() (defaultConfig, error) {
	root, err := defaultAssetRoot()
	if err != nil {
		return defaultConfig{}, err
	}
	data, err := os.ReadFile(filepath.Join(root, "check.yaml"))
	if err != nil {
		return defaultConfig{}, fmt.Errorf("read default config: %w", err)
	}
	var cfg defaultConfig
	if err := yaml.Unmarshal(data, &cfg); err != nil {
		return defaultConfig{}, fmt.Errorf("parse default config: %w", err)
	}
	return cfg, nil
}

func loadRulePack(mode string) ([]ruleSpec, error) {
	root, err := defaultAssetRoot()
	if err != nil {
		return nil, err
	}
	data, err := os.ReadFile(filepath.Join(root, "rules", mode+".yaml"))
	if err != nil {
		return nil, fmt.Errorf("read %s rules: %w", mode, err)
	}
	var pack rulePack
	if err := yaml.Unmarshal(data, &pack); err != nil {
		return nil, fmt.Errorf("parse %s rules: %w", mode, err)
	}
	if pack.Mode != mode {
		return nil, fmt.Errorf("rules file mode %q does not match requested mode %q", pack.Mode, mode)
	}
	return pack.Rules, nil
}

func loadDefaultVocabulary() (Vocabulary, error) {
	root, err := defaultAssetRoot()
	if err != nil {
		return Vocabulary{}, err
	}
	data, err := os.ReadFile(filepath.Join(root, "vocabulary", "default.yaml"))
	if err != nil {
		return Vocabulary{}, fmt.Errorf("read default vocabulary: %w", err)
	}
	var vocab Vocabulary
	if err := yaml.Unmarshal(data, &vocab); err != nil {
		return Vocabulary{}, fmt.Errorf("parse default vocabulary: %w", err)
	}
	return vocab, nil
}

